interface LiveSite {
  name: string;
  domain: string;
  description: string;
}

interface OSSProject {
  name: string;
  repo: string;
  description: string;
  tags: string[];
}

interface MCPServer {
  name: string;
  slug: string;
  description: string;
}

interface HFSpace {
  name: string;
  slug: string;
  description: string;
}

interface PlatformTarget {
  name: string;
  runtime: string;
  description: string;
  repo: string;
}

interface EbookCategory {
  name: string;
  volumes: string;
  count: number;
  titles: string[];
}

interface EcosystemManifest {
  generatedAt: string;
  liveSites: LiveSite[];
  openSource: OSSProject[];
  mcpServers: MCPServer[];
  researchSpaces: HFSpace[];
  platforms: PlatformTarget[];
  ebookCategories: EbookCategory[];
  counts: {
    liveSites: number;
    openSource: number;
    mcpServers: number;
    researchSpaces: number;
    platforms: number;
    ebooks: number;
  };
}

declare const manifest: EcosystemManifest;
export default manifest;
